toolUseResult.originalFile:
# Snowflake — Flow A warehouse datasets (Orders/Payments/Returns/Customer/Product).
# Creates the DB + schema(s) + warehouse + a least-privilege READER role, then grants
# that role to the existing user (DataQ connects as that user — no new password/secret).

resource "snowflake_database" "dataq" {
  name    = var.snowflake_database
  comment = "DataQ harness retail datasets (Flow A)."
}

resource "snowflake_schema" "schemas" {
  for_each = toset(var.snowflake_schemas)
  database = snowflake_database.dataq.name
  name     = each.value
  comment  = "DataQ harness schema."
}

resource "snowflake_warehouse" "dataq" {
  name                = var.snowflake_warehouse
  warehouse_size      = "XSMALL"
  auto_suspend        = 60 # seconds — keep the demo cheap
  auto_resume         = true
  initially_suspended = true
  comment             = "DataQ harness warehouse — checks run here."
}

# Least-privilege read role.
resource "snowflake_account_role" "reader" {
  name    = var.snowflake_reader_role
  comment = "DataQ read-only role: USAGE on db/schema/warehouse + SELECT on tables."
}

# USAGE on the warehouse.
resource "snowflake_grant_privileges_to_account_role" "wh_usage" {
  account_role_name = snowflake_account_role.reader.name
  privileges        = ["USAGE"]
  on_account_object {
    object_type = "WAREHOUSE"
    object_name = snowflake_warehouse.dataq.name
  }
}

# USAGE on the database.
resource "snowflake_grant_privileges_to_account_role" "db_usage" {
  account_role_name = snowflake_account_role.reader.name
  privileges        = ["USAGE"]
  on_account_object {
    object_type = "DATABASE"
    object_name = snowflake_database.dataq.name
  }
}

# USAGE + SELECT on each schema (current + future tables).
resource "snowflake_grant_privileges_to_account_role" "schema_usage" {
  for_each          = snowflake_schema.schemas
  account_role_name = snowflake_account_role.reader.name
  privileges        = ["USAGE"]
  on_schema {
    schema_name = "\"${snowflake_database.dataq.name}\".\"${each.value.name}\""
  }
}

resource "snowflake_grant_privileges_to_account_role" "table_select" {
  for_each          = snowflake_schema.schemas
  account_role_name = snowflake_account_role.reader.name
  privileges        = ["SELECT"]
  on_schema_object {
    future {
      object_type_plural = "TABLES"
      in_schema          = "\"${snowflake_database.dataq.name}\".\"${each.value.name}\""
    }
  }
}

resource "snowflake_grant_privileges_to_account_role" "table_select_existing" {
  for_each          = snowflake_schema.schemas
  account_role_name = snowflake_account_role.reader.name
  privileges        = ["SELECT"]
  on_schema_object {
    all {
      object_type_plural = "TABLES"
      in_schema          = "\"${snowflake_database.dataq.name}\".\"${each.value.name}\""
    }
  }
}

# Grant the reader role to the existing user DataQ authenticates as.
resource "snowflake_grant_account_role" "reader_to_user" {
  role_name = snowflake_account_role.reader.name
  user_name = var.snowflake_reader_user
}

# ---------------------------------------------------------------------------
# Loader (dev) role — the harness ETL (Airflow + ADF) writes with this; it has
# CREATE TABLE + write DML so loads can create/populate the RETAIL tables.
# Kept distinct from the read-only DATAQ_READER that DataQ checks run as.
# ---------------------------------------------------------------------------
resource "snowflake_account_role" "loader" {
  name    = var.snowflake_loader_role
  comment = "DataQ harness ETL role: USAGE + CREATE TABLE + write DML for Airflow/ADF loads."
}

resource "snowflake_grant_privileges_to_account_role" "loader_wh_usage" {
  account_role_name = snowflake_account_role.loader.name
  privileges        = ["USAGE"]
  on_account_object {
    object_type = "WAREHOUSE"
    object_name = snowflake_warehouse.dataq.name
  }
}

resource "snowflake_grant_privileges_to_account_role" "loader_db_usage" {
  account_role_name = snowflake_account_role.loader.name
  privileges        = ["USAGE"]
  on_account_object {
    object_type = "DATABASE"
    object_name = snowflake_database.dataq.name
  }
}

# USAGE + CREATE TABLE on each schema (so a load can create the target table).
resource "snowflake_grant_privileges_to_account_role" "loader_schema" {
  for_each          = snowflake_schema.schemas
  account_role_name = snowflake_account_role.loader.name
  privileges        = ["USAGE", "CREATE TABLE"]
  on_schema {
    schema_name = "\"${snowflake_database.dataq.name}\".\"${each.value.name}\""
  }
}

# Full write DML on current + future tables in each schema.
resource "snowflake_grant_privileges_to_account_role" "loader_tables_future" {
  for_each          = snowflake_schema.schemas
  account_role_name = snowflake_account_role.loader.name
  privileges        = ["SELECT", "INSERT", "UPDATE", "DELETE", "TRUNCATE", "REFERENCES"]
  on_schema_object {
    future {
      object_type_plural = "TABLES"
      in_schema          = "\"${snowflake_database.dataq.name}\".\"${each.value.name}\""
    }
  }
}

resource "snowflake_grant_privileges_to_account_role" "loader_tables_existing" {
  for_each          = snowflake_schema.schemas
  account_role_name = snowflake_account_role.loader.name
  privileges        = ["SELECT", "INSERT", "UPDATE", "DELETE", "TRUNCATE", "REFERENCES"]
  on_schema_object {
    all {
      object_type_plural = "TABLES"
      in_schema          = "\"${snowflake_database.dataq.name}\".\"${each.value.name}\""
    }
  }
}

resource "snowflake_grant_account_role" "loader_to_user" {
  role_name = snowflake_account_role.loader.name
  user_name = var.snowflake_reader_user
}

# CREATE SCHEMA on the database so the self-hosted dbt Core project (dbt/, #609)
# can create + OWN its two lineage schemas (ANALYTICS_STG for staging views,
# ANALYTICS for mart dynamic tables). Owning the schemas lets DATAQ_LOADER create
# views + dynamic tables in them AND grant SELECT/USAGE to DATAQ_READER (dbt
# on-run-end hooks) — so dbt never needs ACCOUNTADMIN. This is the only extra grant
# dbt requires beyond the existing loader write-DML set.
resource "snowflake_grant_privileges_to_account_role" "loader_create_schema" {
  account_role_name = snowflake_account_role.loader.name
  privileges        = ["CREATE SCHEMA"]
  on_account_object {
    object_type = "DATABASE"
    object_name = snowflake_database.dataq.name
  }
}

# ORDERS_HEADER is loaded by the ADF event pipeline (the event modality). The
# Snowflake V2 connector's autoCreate needs connector v1.1, so pre-create the table
# (columns in the source CSV's order for positional COPY mapping). The other Snowflake
# feeds are created on the fly by Airflow's write_pandas (schedule modality).
resource "snowflake_table" "orders_header" {
  database = snowflake_database.dataq.name
  schema   = snowflake_schema.schemas["RETAIL"].name
  name     = "ORDERS_HEADER"

  # Change tracking is a prerequisite for the dbt mart dynamic tables (#609) that
  # read this table via the stg_orders view; DATAQ_LOADER can't enable it itself
  # (it doesn't own the table), so pre-enable here. ADF loads via COPY (INSERT), so
  # unlike the write_pandas feeds this setting persists across loads.
  change_tracking = true

  column {
    name = "ORDER_NUMBER"
    type = "VARCHAR(50)"
  }
  column {
    name = "CUSTOMER_ID"
    type = "VARCHAR(50)"
  }
  column {
    name = "CHANNEL"
    type = "VARCHAR(50)"
  }
  column {
    name = "STORE_ID"
    type = "VARCHAR(50)"
  }
  column {
    name = "PROMO_ID"
    type = "VARCHAR(50)"
  }
  column {
    name = "ORDER_TS"
    type = "TIMESTAMP_NTZ"
  }
  column {
    name = "STATUS"
    type = "VARCHAR(50)"
  }
  column {
    name = "SUBTOTAL"
    type = "NUMBER(38,2)"
  }
  column {
    name = "TAX"
    type = "NUMBER(38,2)"
  }
  column {
    name = "ORDER_TOTAL"
    type = "NUMBER(38,2)"
  }
  column {
    name = "CURRENCY"
    type = "VARCHAR(10)"
  }
}

# CUSTOMERS is loaded by the ADF *timer* (Schedule-trigger) pipeline — pre-created
# for the same reason as ORDERS_HEADER (V2 connector autoCreate needs v1.1). Columns
# in the source CSV's order for positional COPY mapping.
resource "snowflake_table" "customers" {
  database = snowflake_database.dataq.name
  schema   = snowflake_schema.schemas["RETAIL"].name
  name     = "CUSTOMERS"

  column {
