variable "airflow_base_url" {
  description = "External https URL of the Airflow webserver (the Container App ingress FQDN). Pins AIRFLOW__WEBSERVER__BASE_URL so the OAuth redirect URI is built as https behind the TLS-terminating ingress."
  type        = string
  default     = "https://dataq-harness-airflow.purplefield-f7322a1b.westus2.azurecontainerapps.io"
}

variable "airflow_image" {
